// ── HELPERS ──
function getTodayStr() {
  return new Date().toLocaleDateString('en-CA');
}
function formatTime(d) {
  return String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0');
}
function formatDuration(min) {
  if(min==null||isNaN(min)) return '—';
  const h=Math.floor(min/60), m=min%60;
  return h>0?`${h}h ${m}m`:`${m} min`;
}

// ── INIT ──
function init() {
  document.getElementById('hdr-logo').src = SABIL_LOGO_WHITE;
  updateHeaderDate();
  updateClock();
  setInterval(updateClock, 1000);
  // Auto refresh data every 10 seconds
  setInterval(() => { if(window._syncNow) window._syncNow(); }, 10000);
  // Check for midnight rollover every minute
  startMidnightCheck();

  // Set date picker to today
  const picker = document.getElementById('date-picker');
  picker.value = getTodayStr();
  picker.max   = getTodayStr();

  listenToDate(getTodayStr());
}

function updateHeaderDate() {
  const d = new Date();
  const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  document.getElementById('hdr-date').textContent = `${days[d.getDay()]} ${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
}

function updateClock() {
  const n = new Date();
  document.getElementById('hdr-clock').textContent =
    String(n.getHours()).padStart(2,'0')+':'+
    String(n.getMinutes()).padStart(2,'0')+':'+
    String(n.getSeconds()).padStart(2,'0');
}

// ── FIRESTORE REALTIME ──
function listenToDate(dateStr) {
  if(unsubscribe) unsubscribe();
  viewingDate    = dateStr;
  isViewingToday = (dateStr === getTodayStr());

  // UI for past vs today
  document.getElementById('past-badge').style.display = isViewingToday ? 'none' : 'inline-block';
  document.getElementById('btn-stop').disabled   = !isViewingToday;
  document.getElementById('btn-resume').disabled = true;
  document.getElementById('btn-clear').style.display = isViewingToday ? '' : 'none';
  const notesField = document.getElementById('general-notes');
  if(notesField) notesField.disabled = !isViewingToday;
  const ssInput = document.getElementById('shift-start');
  const seInput = document.getElementById('shift-end');
  if(ssInput) ssInput.disabled = !isViewingToday;
  if(seInput) seInput.disabled = !isViewingToday;

  setSyncStatus('loading');

  const ref = doc(db, 'stoppages', dateStr);
  unsubscribe = onSnapshot(ref, async (snap) => {
    if(snap.exists()) {
      stoppages = snap.data().list || [];
      generalNotes = snap.data().generalNotes || '';
      shiftStart = snap.data().shiftStart || '00:00';
      shiftEnd = snap.data().shiftEnd || '23:59';
      targetAchieved = snap.data().targetAchieved || false;
    } else {
      stoppages = [];
      generalNotes = '';
      shiftStart = '00:00';
      shiftEnd = '23:59';
      targetAchieved = false;

      if (isViewingToday) {
        try {
          const prevDate = new Date(dateStr + 'T12:00:00');
          prevDate.setDate(prevDate.getDate() - 1);
          const prevDateStr = prevDate.toLocaleDateString('en-CA');
          const prevRef = doc(db, 'stoppages', prevDateStr);
          const prevSnap = await getDoc(prevRef);

          if (prevSnap.exists()) {
            const prevData = prevSnap.data();
            const prevList = prevData.list || [];
            const openStop = prevList.find(s => !s.end);

            if (openStop) {
              const freshSnap = await getDoc(prevRef);
              const freshList = freshSnap.exists() ? (freshSnap.data().list || []) : [];
              const stillOpen = freshList.find(s => s.id === openStop.id && !s.end);

              if (stillOpen) {
                stillOpen.endDisplay = '23:59';
                stillOpen.end = new Date(prevDateStr + 'T23:59:00').toISOString();
                const [sh, sm] = stillOpen.startDisplay.split(':');
                stillOpen.durationMin = (23*60+59) - (parseInt(sh)*60 + parseInt(sm));
                await setDoc(prevRef, {
                  ...freshSnap.data(),
                  list: freshList,
                  updatedAt: new Date().toISOString()
                });

                const newStop = {
                  id: Date.now(),
                  start: new Date(dateStr + 'T00:00:00').toISOString(),
                  startDisplay: '00:00',
                  end: null, endDisplay: null,
                  reason: stillOpen.reason, party: stillOpen.party,
                  notes: 'Continued from previous day',
                  durationMin: null
                };
                stoppages = [newStop];
                targetAchieved = false;
                await saveToFirestore();
              }
            } else if (prevData.targetAchieved) {
              targetAchieved = true;
              await saveToFirestore();
            }
          }
        } catch(e) {
          console.error('Previous day check failed:', e);
        }
      }
    }
    const notesEl = document.getElementById('general-notes');
    if(notesEl && notesEl !== document.activeElement) notesEl.value = generalNotes;
    const ssEl = document.getElementById('shift-start');
    const seEl = document.getElementById('shift-end');
    if(ssEl) ssEl.value = shiftStart;
    if(seEl) seEl.value = shiftEnd;

    // Restore active stop
    const active = isViewingToday ? stoppages.find(s=>!s.end) : null;
    if(targetAchieved && !active) {
      currentStop = null;
      stopElapsedTimer();
      setTargetAchievedUI();
    } else if(active) {
      currentStop = active;
      setStoppedUI();
      startElapsedTimer();
    } else if(!active && currentStop) {
      currentStop = null;
      stopElapsedTimer();
      setRunningUI();
    } else if(!active && !currentStop) {
      setRunningUI();
    }

    setSyncStatus('live');
    renderAll();
  }, (err) => {
    console.error(err);
    setSyncStatus('error');
  });
}

// ── MIDNIGHT ROLLOVER ──
// Check every minute if day has changed while a stoppage is ongoing
function startMidnightCheck() {
  setInterval(async () => {
    const today = getTodayStr();
    if (viewingDate !== today && currentStop) {
      // Day changed with an open stoppage — close it at 23:59 on the old day
      currentStop.endDisplay  = '23:59';
      currentStop.end = new Date(`${viewingDate}T23:59:00`).toISOString();
      const [sh, sm] = currentStop.startDisplay.split(':');
      currentStop.durationMin = (23*60+59) - (parseInt(sh)*60+parseInt(sm));
      await saveToFirestore();

      // Switch to new day and open a new stoppage from 00:00
      const oldParty  = currentStop.party;
      const oldReason = currentStop.reason;
      currentStop = null;
      stopElapsedTimer();

      // Switch to today
      listenToDate(today);
      document.getElementById('date-picker').value = today;

      // After short delay, create new stoppage on new day
      setTimeout(async () => {
        const now = new Date();
        const newStop = {
          id: Date.now(),
          start: new Date(`${today}T00:00:00`).toISOString(),
          startDisplay: '00:00',
          end: null, endDisplay: null,
          reason: oldReason, party: oldParty,
          notes: 'Continued from previous day',
          durationMin: null
        };
        stoppages.push(newStop);
        currentStop = newStop;
        await saveToFirestore();
        setStoppedUI();
        startElapsedTimer();
      }, 2000);
    }
  }, 60000); // check every minute
}

async function saveToFirestore() {
  try {
    const ref = doc(db, 'stoppages', viewingDate);
    await setDoc(ref, { list: stoppages, generalNotes: generalNotes, shiftStart: shiftStart, shiftEnd: shiftEnd, targetAchieved: targetAchieved, updatedAt: new Date().toISOString() });
  } catch(e) {
    console.error(e);
    setSyncStatus('error');
  }
}

function setSyncStatus(state) {
  const dot = document.getElementById('sync-dot');
  const lbl = document.getElementById('sync-label');
  if(state==='live') {
    dot.className='sync-dot live';
    const t = new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});
    lbl.innerHTML=`<strong>🟢 Live — Shared with team</strong> &nbsp;·&nbsp; ${t}`;
  } else if(state==='loading') {
    dot.className='sync-dot';
    lbl.innerHTML='Syncing...';
  } else {
    dot.className='sync-dot err';
    lbl.innerHTML='⚠️ Connection error';
  }
}

window._syncNow = () => listenToDate(viewingDate);

window._saveGeneralNotes = () => {
  generalNotes = document.getElementById('general-notes').value;
  if(notesTimer) clearTimeout(notesTimer);
  notesTimer = setTimeout(() => saveToFirestore(), 1000);
};

const ADMIN_PIN = '1234';

window._saveShiftTimes = () => {
  const pin = prompt('Enter admin PIN to change shift times:');
  if (pin !== ADMIN_PIN) {
    alert('Incorrect PIN');
    document.getElementById('shift-start').value = shiftStart;
    document.getElementById('shift-end').value = shiftEnd;
    return;
  }
  shiftStart = document.getElementById('shift-start').value || '00:00';
  shiftEnd = document.getElementById('shift-end').value || '23:59';
  saveToFirestore();
};

window._onDateChange = () => {
  const val = document.getElementById('date-picker').value;
  if(val) listenToDate(val);
};

