window._selectParty = async (party, cls, btn) => {
  if (party === 'Completed') {
    targetAchieved = true;
    await saveToFirestore();
    closeModal();
    setTargetAchievedUI();
    renderAll();
    return;
  }
  selectedParty=party; selectedReason='';
  document.querySelectorAll('.party-btn').forEach(b=>b.className='party-btn');
  btn.classList.add(cls);
  const meta=PARTY_META[party];
  const grid=document.getElementById('sub-grid');
  grid.innerHTML='';
  SUB_REASONS[party].forEach(r=>{
    const chip=document.createElement('button');
    chip.className=`sub-chip ${meta.cls}`;
    chip.textContent=r;
    chip.onclick=()=>selectSubReason(chip,r);
    grid.appendChild(chip);
  });
  const badge=document.getElementById('party-badge');
  badge.style.cssText=meta.badge+';display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;';
  badge.innerHTML=`<img src="${meta.logo}" style="height:18px;object-fit:contain"> ${party}`;
  document.getElementById('step1').style.display='none';
  document.getElementById('step2').style.display='';
  document.getElementById('sd1').className='step-dot done';
  document.getElementById('sl1').className='step-line done';
  document.getElementById('sd2').className='step-dot active';
  document.getElementById('step-lbl').textContent='Select Reason';
};

function selectSubReason(el,reason) {
  document.getElementById('sub-grid').querySelectorAll('.sub-chip').forEach(c=>c.classList.remove('chosen'));
  el.classList.add('chosen');
  selectedReason=reason;
}

window._goBackStep1 = () => { selectedReason=''; selectedParty=''; showStep1(); };
window.closeModal  = () => document.getElementById('modal-overlay').classList.remove('show');

window._confirmStop = async () => {
  if(!selectedParty) { alert('Please select a party first'); return; }
  if(!selectedReason) { alert('Please select a stoppage reason'); return; }
  const notes=document.getElementById('modal-notes').value.trim();
  const now=new Date();
  currentStop={
    id:Date.now(),
    start:now.toISOString(), startDisplay:formatTime(now),
    end:null, endDisplay:null,
    reason:selectedReason, party:selectedParty,
    notes:notes, durationMin:null
  };
  stoppages.push(currentStop);
  await saveToFirestore();
  closeModal();
  setStoppedUI();
  startElapsedTimer();
};

window._resumeTransfer = async () => {
  if(targetAchieved && !currentStop) {
    targetAchieved = false;
    await saveToFirestore();
    setRunningUI();
    renderAll();
    return;
  }
  if(!currentStop) return;
  const now=new Date();
  const diffMin=Math.round((now-new Date(currentStop.start))/60000);
  currentStop.end=now.toISOString();
  currentStop.endDisplay=formatTime(now);
  currentStop.durationMin=diffMin;
  currentStop=null;
  stopElapsedTimer();
  await saveToFirestore();
  setRunningUI();
};

// ── TIMERS ──
function startElapsedTimer() {
  stopElapsedTimer();
  timerInterval=setInterval(()=>{
    if(!currentStop) return;
    const elapsed=Math.floor((Date.now()-new Date(currentStop.start))/1000);
    const h=Math.floor(elapsed/3600),m=Math.floor((elapsed%3600)/60),s=elapsed%60;
    const txt=h>0?`${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`:`${m}:${String(s).padStart(2,'0')}`;
    document.getElementById('status-elapsed').innerHTML=`Current stoppage: <span>${txt}</span>`;
    const el=document.getElementById('ongoing-duration');
    if(el) el.textContent=txt;
  },1000);
}
function stopElapsedTimer() { if(timerInterval){clearInterval(timerInterval);timerInterval=null;} }

