// ── RENDER ──
function renderAll() { renderDashboard(); renderLog(); renderStats(); renderExport(); }

function renderDashboard() {
  const sabilLogoEl = document.getElementById('ops-sabil-logo');
  const millsLogoEl = document.getElementById('ops-mills-logo');
  if(sabilLogoEl && !sabilLogoEl.src.startsWith('data:')) sabilLogoEl.src = SABIL_LOGO;
  if(millsLogoEl && !millsLogoEl.src.startsWith('data:')) millsLogoEl.src = MILLS_LOGO;
  const sabilAll = stoppages.filter(s => s.party === 'Sabil');
  const millsAll = stoppages.filter(s => s.party === 'Mills');
  const sabilDone = sabilAll.filter(s => s.end);
  const millsDone = millsAll.filter(s => s.end);
  const sabilMin = sabilDone.reduce((a, s) => a + s.durationMin, 0);
  const millsMin = millsDone.reduce((a, s) => a + s.durationMin, 0);

  document.getElementById('ops-sabil-count').textContent = sabilAll.length + ' stop' + (sabilAll.length !== 1 ? 's' : '');
  document.getElementById('ops-sabil-time').textContent = sabilMin > 0 ? formatDuration(sabilMin) + ' downtime' : 'No downtime';
  document.getElementById('ops-mills-count').textContent = millsAll.length + ' stop' + (millsAll.length !== 1 ? 's' : '');
  document.getElementById('ops-mills-time').textContent = millsMin > 0 ? formatDuration(millsMin) + ' downtime' : 'No downtime';

  const dot = document.getElementById('ops-status-dot');
  const txt = document.getElementById('ops-status-text');
  const card = document.getElementById('ops-status-card');
  if (targetAchieved && !currentStop) {
    dot.innerHTML = ICON_FLAG;
    dot.style.background = 'none';
    dot.style.boxShadow = 'none';
    txt.textContent = 'Completed';
    txt.style.color = '#1A6B4A';
    card.style.borderLeftColor = '#1A6B4A';
  } else if (currentStop) {
    dot.innerHTML = '';
    dot.style.background = '#C0392B';
    dot.style.boxShadow = '0 0 0 3px rgba(192,57,43,0.2)';
    txt.textContent = 'Stopped';
    txt.style.color = '#C0392B';
    card.style.borderLeftColor = '#C0392B';
  } else {
    dot.innerHTML = ICON_GEARS;
    dot.style.background = 'none';
    dot.style.boxShadow = 'none';
    txt.textContent = 'Running';
    txt.style.color = '#1A6B4A';
    card.style.borderLeftColor = '#1A6B4A';
  }

  const lastEl = document.getElementById('ops-last-text');
  const lastDetail = document.getElementById('ops-last-detail');
  if (stoppages.length > 0) {
    const last = stoppages[stoppages.length - 1];
    const timeStr = last.endDisplay ? last.endDisplay : last.startDisplay;
    lastEl.textContent = last.reason;
    lastDetail.textContent = (last.end ? 'Ended ' : 'Started ') + timeStr + ' — ' + last.party;
  } else {
    lastEl.textContent = '—';
    lastDetail.textContent = 'No stoppages recorded';
  }
}

function renderLog() {
  const list=document.getElementById('log-list');
  const count=document.getElementById('log-count');
  if(!stoppages.length) {
    list.innerHTML='<div class="log-empty">No stoppages recorded yet<br><small>Press "Log Stoppage" when transfer stops</small></div>';
    count.textContent='0 Stoppages'; return;
  }
  count.textContent=`${stoppages.length} Stoppages`;
  list.innerHTML='';
  [...stoppages].reverse().forEach((s,idx)=>{
    const num=stoppages.length-idx;
    const isOngoing=!s.end;
    const dur=isOngoing?'⏱':formatDuration(s.durationMin);
    const party=s.party||'';
    let pStyle='',pIcon='';
    if(party==='Mills'){pStyle='background:#EAF0FB;color:#1A4D6E;border:1px solid #93C5FD';pIcon=MILLS_LOGO;}
    else{pStyle='background:#E6F5EE;color:#1A6B4A;border:1px solid #6EE7B7';pIcon=SABIL_LOGO;}
    const canDelete = isViewingToday && !isOngoing;
    const canEdit   = isViewingToday && !isOngoing;
    const div=document.createElement('div');
    div.className='log-item';
    div.innerHTML=`
      <div class="log-item-header">
        <div style="display:flex;align-items:center;gap:7px;flex-wrap:wrap">
          <div class="log-num">${num}</div>
          <span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:20px;${pStyle};display:inline-flex;align-items:center;gap:4px">
            <img src="${pIcon}" style="height:14px;object-fit:contain"> ${party}
          </span>
          <div class="log-reason">${s.reason}</div>
        </div>
        <div style="display:flex;align-items:center;gap:5px">
          <span class="log-duration ${isOngoing?'ongoing':''}" ${isOngoing?'id="ongoing-duration"':''}>${dur}</span>
          ${canEdit?`<button class="edit-btn" onclick="editStop(${s.id})" title="Edit time">✏️</button>`:''}
          ${canDelete?`<button class="delete-btn" onclick="deleteStop(${s.id})" title="Delete">✕</button>`:''}
        </div>
      </div>
      <div class="log-times">Start: ${s.startDisplay} &nbsp;|&nbsp; End: ${s.endDisplay||'—'}</div>
      ${s.notes?`<div class="log-notes-text">📝 ${s.notes}</div>`:''}`;
    list.appendChild(div);
  });
}

function renderStats() {
  const done=stoppages.filter(s=>s.end);
  const total=done.reduce((a,s)=>a+s.durationMin,0);
  const longest=done.length?Math.max(...done.map(s=>s.durationMin)):0;
  document.getElementById('stat-count').textContent=stoppages.length;
  document.getElementById('stat-total').textContent=total>0?formatDuration(total):'0:00';
  document.getElementById('stat-longest').textContent=longest>0?formatDuration(longest):'—';
}

function renderExport() {
  const el=document.getElementById('export-text');
  const done=stoppages.filter(s=>s.end);
  if(!stoppages.length){el.textContent='No stoppages recorded today.';return;}
  const total=done.reduce((a,s)=>a+s.durationMin,0);
  const mills=done.filter(s=>s.party==='Mills');
  const sabil=done.filter(s=>s.party==='Sabil');
  const d=new Date(viewingDate+'T12:00:00');
  const days=['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const months=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const dateLabel=`${days[d.getDay()]} ${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
  let txt=`Operational Stoppages — ${dateLabel}
${'-'.repeat(42)}
`;
  txt+=`Total: ${stoppages.length}${currentStop?' (ongoing)':''}  |  Time: ${formatDuration(total)}
`;
  if(mills.length) txt+=`🏭 Modern Mills: ${mills.length} — ${formatDuration(mills.reduce((a,s)=>a+s.durationMin,0))}
`;
  if(sabil.length) txt+=`🚛 Sabil: ${sabil.length} — ${formatDuration(sabil.reduce((a,s)=>a+s.durationMin,0))}
`;
  txt+=`${'-'.repeat(42)}
`;
  stoppages.forEach((s,i)=>{
    const dur=s.durationMin!=null?formatDuration(s.durationMin):'Ongoing';
    const icon=s.party==='Mills'?'🏭':'🚛';
    txt+=`
${i+1}. ${icon} [${s.party}] ${s.reason}
`;
    txt+=`   From: ${s.startDisplay} → To: ${s.endDisplay||'Ongoing'} (${dur})
`;
    if(s.notes) txt+=`   Note: ${s.notes}
`;
  });
  el.textContent=txt;
}

window._deleteStop = async (id) => {
  if(!confirm('Delete this stoppage?')) return;
  stoppages=stoppages.filter(s=>s.id!==id);
  await saveToFirestore();
};

window._clearAll = async () => {
  const pin = prompt('Enter admin PIN to clear all stoppages:');
  if (pin !== ADMIN_PIN) { alert('Incorrect PIN'); return; }
  if(!confirm('Clear all stoppages for today?')) return;
  stoppages=[]; currentStop=null; stopElapsedTimer();
  generalNotes='';
  const notesEl = document.getElementById('general-notes');
  if(notesEl) notesEl.value = '';
  await saveToFirestore();
  setRunningUI();
};

window._printPDF = async () => {
  const [ssH, ssM] = shiftStart.split(':').map(Number);
  const [seH, seM] = shiftEnd.split(':').map(Number);
  const shiftStartMin = ssH * 60 + ssM;
  const shiftEndMin = seH * 60 + seM;
  const crossesMidnight = shiftStartMin >= shiftEndMin;

  let shiftMinutes = crossesMidnight
    ? (1440 - shiftStartMin) + shiftEndMin
    : shiftEndMin - shiftStartMin;
  if (shiftMinutes <= 0) shiftMinutes = 1440;

  function getStopMinute(s) {
    if (!s.startDisplay) return 0;
    const [h, m] = s.startDisplay.split(':').map(Number);
    return h * 60 + m;
  }

  let shiftStoppages = [];

  if (crossesMidnight) {
    const todayFiltered = stoppages.filter(s => getStopMinute(s) < shiftEndMin);

    const prevDate = new Date(viewingDate + 'T12:00:00');
    prevDate.setDate(prevDate.getDate() - 1);
    const prevDateStr = prevDate.toLocaleDateString('en-CA');
    let prevStoppages = [];
    try {
      const prevRef = doc(db, 'stoppages', prevDateStr);
      const prevSnap = await getDoc(prevRef);
      if (prevSnap.exists()) prevStoppages = prevSnap.data().list || [];
    } catch(e) { console.error('Failed to load previous day:', e); }
    const prevFiltered = prevStoppages.filter(s => getStopMinute(s) >= shiftStartMin);

    shiftStoppages = [...prevFiltered, ...todayFiltered];
  } else {
    shiftStoppages = stoppages.filter(s => {
      const m = getStopMinute(s);
      return m >= shiftStartMin && m < shiftEndMin;
    });
  }

  const done = shiftStoppages.filter(s => s.end);
  const totalMin = done.reduce((a, s) => a + s.durationMin, 0);
  const millsAll = shiftStoppages.filter(s => s.party === 'Mills');
  const sabilAll = shiftStoppages.filter(s => s.party === 'Sabil');
  const millsDone = done.filter(s => s.party === 'Mills');
  const sabilDone = done.filter(s => s.party === 'Sabil');
  const millsMin = millsDone.reduce((a, s) => a + s.durationMin, 0);
  const sabilMin = sabilDone.reduce((a, s) => a + s.durationMin, 0);

  const d = new Date(viewingDate + 'T12:00:00');
  const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const dateStr = `${days[d.getDay()]} ${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;

  const runningMin = shiftMinutes - totalMin;
  const availability = shiftMinutes > 0 ? ((runningMin / shiftMinutes) * 100).toFixed(2) : '0.00';
  const hasOngoing = shiftStoppages.some(s => !s.end);
  let statusText, statusColor, statusSub;
  if(targetAchieved && !hasOngoing) {
    statusText = 'COMPLETED'; statusColor = '#1A6B4A'; statusSub = 'Transfer Completed';
  } else if(hasOngoing) {
    statusText = 'STOPPED'; statusColor = '#C0392B'; statusSub = 'Stoppage Active';
  } else {
    statusText = 'RUNNING'; statusColor = '#27AE60'; statusSub = 'Plant is Operating';
  }

  const longest = done.length ? done.reduce((a, s) => s.durationMin > a.durationMin ? s : a, done[0]) : null;

  const reasonCounts = {};
  done.forEach(s => { reasonCounts[s.reason] = (reasonCounts[s.reason] || 0) + 1; });
  const topReason = Object.keys(reasonCounts).length ? Object.entries(reasonCounts).sort((a, b) => b[1] - a[1])[0] : null;

  const millsAvg = millsDone.length ? Math.round(millsMin / millsDone.length) : 0;
  const sabilAvg = sabilDone.length ? Math.round(sabilMin / sabilDone.length) : 0;
  const totalDown = millsMin + sabilMin;
  const millsPct = totalDown > 0 ? Math.round((millsMin / totalDown) * 100) : 0;
  const sabilPct = totalDown > 0 ? Math.round((sabilMin / totalDown) * 100) : 0;

  function buildPartyTable(partyStops, partyName, borderColor, bgColor, hdrBg, txtColor) {
    const pDone = partyStops.filter(s => s.end);
    const pTotal = pDone.reduce((a, s) => a + s.durationMin, 0);
    let trs = '';
    partyStops.forEach((s, i) => {
      const dur = s.durationMin != null ? formatDuration(s.durationMin) : '<span style="color:#C0392B;font-weight:700">Ongoing</span>';
      const cat = REASON_CATEGORIES[s.reason] || 'Other';
      const cs = CATEGORY_STYLES[cat] || CATEGORY_STYLES['Other'];
      const status = s.end
        ? '<span style="background:#E6F5EE;color:#1A6B4A;padding:2px 8px;border-radius:12px;font-size:10px;font-weight:600">Completed</span>'
        : '<span style="background:#FDECEA;color:#C0392B;padding:2px 8px;border-radius:12px;font-size:10px;font-weight:600">Active</span>';
      trs += `<tr${i % 2 === 1 ? ' style="background:#FAFCFB"' : ''}>
        <td style="text-align:center;color:#666;border-bottom:1px solid ${bgColor}">${i + 1}</td>
        <td style="border-bottom:1px solid ${bgColor};font-weight:600;color:${txtColor}">${partyName}</td>
        <td style="border-bottom:1px solid ${bgColor};font-weight:600">${s.reason}</td>
        <td style="border-bottom:1px solid ${bgColor}"><span style="background:${cs.bg};color:${cs.color};padding:2px 8px;border-radius:12px;font-size:10px;font-weight:600">${cat}</span></td>
        <td style="text-align:center;border-bottom:1px solid ${bgColor}">${s.startDisplay}</td>
        <td style="text-align:center;border-bottom:1px solid ${bgColor}">${s.endDisplay || '—'}</td>
        <td style="text-align:center;border-bottom:1px solid ${bgColor};font-weight:700;color:#C0392B">${dur}</td>
        <td style="text-align:center;border-bottom:1px solid ${bgColor}">${status}</td></tr>`;
    });
    return `<div style="border:1px solid ${borderColor};border-radius:8px;overflow:hidden;break-inside:avoid">
      <div style="background:${bgColor};padding:6px 12px;display:flex;justify-content:space-between;align-items:center">
        <div style="display:flex;align-items:center;gap:6px"><span style="font-size:18px;font-weight:700;color:${txtColor}">${partyStops.length}</span><span style="font-size:12px;color:${txtColor}">Total Stoppages (${partyName})</span></div>
        <div style="font-size:11px;color:${txtColor}">${formatDuration(pTotal)} Total Downtime</div>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:11px">
        <thead><tr style="background:${hdrBg}">
          <th style="padding:6px 8px;text-align:center;font-weight:600;color:${txtColor};width:28px">#</th>
          <th style="padding:6px 8px;text-align:left;font-weight:600;color:${txtColor}">Party</th>
          <th style="padding:6px 8px;text-align:left;font-weight:600;color:${txtColor}">Stoppage Reason</th>
          <th style="padding:6px 8px;text-align:left;font-weight:600;color:${txtColor}">Category</th>
          <th style="padding:6px 8px;text-align:center;font-weight:600;color:${txtColor}">Start</th>
          <th style="padding:6px 8px;text-align:center;font-weight:600;color:${txtColor}">End</th>
          <th style="padding:6px 8px;text-align:center;font-weight:600;color:${txtColor}">Duration</th>
          <th style="padding:6px 8px;text-align:center;font-weight:600;color:${txtColor}">Status</th>
        </tr></thead>
        <tbody>${trs}</tbody>
      </table></div>`;
  }

  const sabilTable = sabilAll.length ? buildPartyTable(sabilAll, 'Sabil', '#6EE7B7', '#E6F5EE', '#F0F9F4', '#1A6B4A') : '';
  const millsTable = millsAll.length ? buildPartyTable(millsAll, 'Mills', '#93C5FD', '#EAF0FB', '#F0F4FB', '#1A4D6E') : '';

  const availBadge = parseFloat(availability) >= 95
    ? '<span style="background:#E6F5EE;color:#1A6B4A;padding:3px 10px;border-radius:12px;font-size:10px;font-weight:600">Above 95% target</span>'
    : '<span style="background:#FEF3E7;color:#D4680A;padding:3px 10px;border-radius:12px;font-size:10px;font-weight:600">Below 95% target</span>';

  const w = window.open('', '_blank', 'width=1000,height=800');
  w.document.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Stoppage Report</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:'Inter',sans-serif;color:#1A2E24;padding:20px 24px;font-size:12px}
    @media print{@page{size:A4 landscape;margin:12mm}}
  </style></head><body>

  <!-- HEADER -->
  <div style="display:flex;align-items:center;justify-content:space-between;padding-bottom:10px;border-bottom:3px solid #1A6B4A;margin-bottom:14px">
    <img src="${SABIL_LOGO}" style="height:44px;object-fit:contain" alt="Sabil">
    <div style="text-align:center;flex:1">
      <div style="font-size:17px;font-weight:700;color:#1A6B4A;text-transform:uppercase;letter-spacing:0.5px">Daily Operational Stoppage Report</div>
      <div style="font-size:11px;color:#888;margin-top:2px">Wheat Transfer Operations — Silos</div>
    </div>
    <div style="text-align:right;font-size:11px;color:#555;line-height:1.7">
      <div>${dateStr}</div>
      <div>Printed at: ${new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'})}</div>
      <div>Shift: ${shiftStart} — ${shiftEnd}</div>
    </div>
  </div>

  <!-- OPERATIONAL HEALTH BANNER -->
  <div style="background:linear-gradient(135deg,#124D36,#1A6B4A);border-radius:6px;padding:5px 14px;text-align:center;margin-bottom:12px">
    <span style="color:#fff;font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:1px">Today's Operational Health</span>
  </div>

  <!-- KPI CARDS -->
  <div style="display:flex;gap:8px;margin-bottom:14px">
    <div style="flex:1;border:1px solid #D0E4D9;border-radius:8px;padding:10px 8px;text-align:center;background:#F8FBF9">
      <svg width="32" height="20" viewBox="0 0 44 24" style="margin:0 auto 4px;display:block">${(()=>{const r=16,cx=22,cy=21,sw=5,pct=Math.min(Math.max(parseFloat(availability),0),100)/100,sx=cx-r,sy=cy,ex=cx+r,ey=cy,bg='M'+sx+' '+sy+' A'+r+' '+r+' 0 1 1 '+ex+' '+ey,pa=Math.PI*(1-pct),px=(cx+r*Math.cos(pa)).toFixed(2),py=(cy-r*Math.sin(pa)).toFixed(2),lg=pct>0.5?1:0,prog='M'+sx+' '+sy+' A'+r+' '+r+' 0 '+lg+' 1 '+px+' '+py;return'<path d="'+bg+'" fill="none" stroke="#A8E6CC" stroke-width="'+sw+'" stroke-linecap="round"/>'+(pct>0.01?'<path d="'+prog+'" fill="none" stroke="#1A6B4A" stroke-width="'+sw+'" stroke-linecap="round"/>':'')})()}</svg>
      <div style="font-size:9px;color:#5C7A69;text-transform:uppercase;margin-bottom:2px">Availability</div>
      <div style="font-size:22px;font-weight:700;color:#1A6B4A">${availability}%</div>
      <div style="font-size:9px;color:#999">Target > 95%</div>
    </div>
    <div style="flex:1;border:1px solid #D0E4D9;border-radius:8px;padding:10px 8px;text-align:center;background:#F8FBF9">
      <svg width="28" height="28" viewBox="0 0 24 24" style="margin:0 auto 4px;display:block" fill="none" stroke="#1A73E8" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="6" x2="12" y2="12"/><line x1="12" y1="12" x2="16" y2="14"/></svg>
      <div style="font-size:9px;color:#5C7A69;text-transform:uppercase;margin-bottom:2px">Running Time</div>
      <div style="font-size:22px;font-weight:700;color:#1A6B4A">${formatDuration(runningMin)}</div>
      <div style="font-size:9px;color:#999">Since ${shiftStart}</div>
    </div>
    <div style="flex:1;border:1px solid #F5C4C4;border-radius:8px;padding:10px 8px;text-align:center;background:#FEF5F5">
      <svg width="28" height="28" viewBox="0 0 28 24" style="margin:0 auto 4px;display:block" fill="none"><circle cx="11" cy="12" r="10" stroke="#C0392B" stroke-width="2"/><line x1="11" y1="6" x2="11" y2="12" stroke="#C0392B" stroke-width="2" stroke-linecap="round"/><line x1="11" y1="12" x2="15" y2="14" stroke="#C0392B" stroke-width="2" stroke-linecap="round"/><circle cx="23" cy="16" r="5" fill="#C0392B"/><line x1="23" y1="13" x2="23" y2="16.5" stroke="#fff" stroke-width="1.8" stroke-linecap="round"/><circle cx="23" cy="18.5" r="0.8" fill="#fff"/></svg>
      <div style="font-size:9px;color:#91403A;text-transform:uppercase;margin-bottom:2px">Downtime</div>
      <div style="font-size:22px;font-weight:700;color:#C0392B">${formatDuration(totalMin)}</div>
      <div style="font-size:9px;color:#999">Total Downtime</div>
    </div>
    <div style="flex:1;border:1px solid #F5D5A8;border-radius:8px;padding:10px 8px;text-align:center;background:#FFFBF5">
      <svg width="28" height="28" viewBox="0 0 24 24" style="margin:0 auto 4px;display:block" fill="none" stroke="#D4680A" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
      <div style="font-size:9px;color:#8B5E1A;text-transform:uppercase;margin-bottom:2px">Total Stops</div>
      <div style="font-size:22px;font-weight:700;color:#D4680A">${shiftStoppages.length}</div>
      <div style="font-size:9px;color:#999">Total Stoppages</div>
    </div>
    <div style="flex:1;border:1px solid #D0E4D9;border-radius:8px;padding:10px 8px;text-align:center;background:#F0F9F4">
      <div style="margin:0 auto 4px;width:28px;height:28px;display:flex;align-items:center;justify-content:center">${statusText==='RUNNING'?'<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#1A6B4A" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>':statusText==='COMPLETED'?'<svg width="24" height="24" viewBox="0 0 24 24" fill="none"><rect x="4" y="2" width="2" height="20" rx="0.5" fill="#222"/><rect x="6" y="2" width="4" height="3" fill="#222"/><rect x="14" y="2" width="4" height="3" fill="#222"/><rect x="10" y="5" width="4" height="3" fill="#222"/><rect x="18" y="5" width="2" height="3" fill="#222"/><rect x="6" y="8" width="4" height="3" fill="#222"/><rect x="14" y="8" width="4" height="3" fill="#222"/><rect x="10" y="11" width="4" height="3" fill="#222"/><rect x="18" y="11" width="2" height="3" fill="#222"/><rect x="6" y="2" width="14" height="12" rx="1" fill="none" stroke="#222" stroke-width="1"/></svg>':'<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#C0392B" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><rect x="9" y="9" width="6" height="6" rx="1" fill="#C0392B"/></svg>'}</div>
      <div style="font-size:9px;color:#5C7A69;text-transform:uppercase;margin-bottom:2px">Current Status</div>
      <div style="font-size:13px;font-weight:700;color:${statusColor}">${statusText}</div>
      <div style="font-size:9px;color:#999">${statusSub}</div>
    </div>
  </div>

  <!-- PARTY TABLES -->
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px">
    ${sabilTable}${millsTable}
  </div>

  <!-- BOTTOM SECTIONS -->
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px">
    <!-- DOWNTIME BREAKDOWN -->
    <div style="border:1px solid #D0E4D9;border-radius:8px;padding:12px 14px">
      <div style="font-size:11px;font-weight:700;color:#1A6B4A;text-transform:uppercase;margin-bottom:8px">Downtime Breakdown</div>
      <div style="margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:3px"><span style="color:#1A4D6E;font-weight:600">Mills</span><span style="font-weight:700">${formatDuration(millsMin)}</span></div>
        <div style="background:#E8E8E8;border-radius:4px;height:8px;overflow:hidden"><div style="background:#1A4D6E;height:100%;width:${millsPct}%;border-radius:4px"></div></div>
      </div>
      <div style="margin-bottom:10px">
        <div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:3px"><span style="color:#1A6B4A;font-weight:600">Sabil</span><span style="font-weight:700">${formatDuration(sabilMin)}</span></div>
        <div style="background:#E8E8E8;border-radius:4px;height:8px;overflow:hidden"><div style="background:#1A6B4A;height:100%;width:${sabilPct}%;border-radius:4px"></div></div>
      </div>
      <div style="border-top:1px solid #E8E8E8;padding-top:8px;font-size:10px;color:#666">
        <div style="display:flex;justify-content:space-between;margin-bottom:3px"><span>Longest Stoppage</span><span style="font-weight:700">${longest ? formatDuration(longest.durationMin) + ' (' + longest.reason + ')' : '—'}</span></div>
        <div style="display:flex;justify-content:space-between"><span>Most Frequent</span><span style="font-weight:700">${topReason ? topReason[0] + ' (' + topReason[1] + 'x)' : '—'}</span></div>
      </div>
    </div>
    <!-- KEY HIGHLIGHTS -->
    <div style="border:1px solid #D0E4D9;border-radius:8px;padding:12px 14px">
      <div style="font-size:11px;font-weight:700;color:#1A6B4A;text-transform:uppercase;margin-bottom:8px">Key Highlights</div>
      <div style="font-size:11px;color:#333;line-height:2">
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Mills avg. stop</span><span style="font-weight:700">${millsAvg} min</span></div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Sabil avg. stop</span><span style="font-weight:700">${sabilAvg} min</span></div>
        <div style="display:flex;justify-content:space-between"><span style="color:#888">Total stoppages</span><span style="font-weight:700">Mills: ${millsAll.length} / Sabil: ${sabilAll.length}</span></div>
      </div>
      <div style="font-size:11px;font-weight:700;color:#1A6B4A;text-transform:uppercase;margin-top:10px;margin-bottom:6px">Availability Result</div>
      <div style="display:flex;align-items:center;gap:8px">
        <span style="background:#1A6B4A;color:#fff;padding:4px 12px;border-radius:8px;font-size:14px;font-weight:700">${availability}%</span>
        ${availBadge}
      </div>
    </div>
  </div>

  <!-- GENERAL NOTES -->
  <div style="border:1px solid #D0E4D9;border-radius:8px;padding:12px 14px;margin-bottom:14px">
    <div style="font-size:11px;font-weight:700;color:#1A6B4A;text-transform:uppercase;margin-bottom:6px">General Notes</div>
    <div style="font-size:11px;color:#555;min-height:20px;white-space:pre-wrap">${generalNotes || ''}</div>
    <div style="border-bottom:1px solid #ddd;margin-top:8px"></div>
    <div style="border-bottom:1px solid #ddd;margin-top:10px"></div>
  </div>

  <!-- SIGNATURES -->
  <div style="display:flex;justify-content:space-around;align-items:flex-end;margin-bottom:14px">
    <div style="text-align:center">
      <div style="border-top:1px solid #999;width:160px;margin-bottom:4px"></div>
      <div style="font-size:11px;color:#555;font-weight:600">Control Room Operator</div>
    </div>
    <div style="text-align:center">
      <div style="border-top:1px solid #999;width:160px;margin-bottom:4px"></div>
      <div style="font-size:11px;color:#555;font-weight:600">Direct Supervisor</div>
    </div>
  </div>

  <!-- FOOTER -->
  <div style="display:flex;justify-content:space-between;border-top:1px solid #ddd;padding-top:8px;font-size:10px;color:#aaa">
    <span>Sabil Stoppage Tracker v1.1 — Developed by Eng. Mohammed Kufiyyah</span>
    <span>${dateStr}</span>
  </div>

  <script>window.onload=()=>window.print()<\/script></body></html>`);
  w.document.close();
};

// ── EDIT STOP ──
let editingStopId = null;

window._editStop = (id) => {
  const s = stoppages.find(x => x.id === id);
  if (!s) return;
  editingStopId = id;
  // Set hour/minute selects
  const [sh, sm] = (s.startDisplay || '00:00').split(':');
  document.getElementById('edit-start-h').value = sh || '00';
  document.getElementById('edit-start-m').value = sm || '00';
  if (s.endDisplay) {
    const [eh, em] = s.endDisplay.split(':');
    document.getElementById('edit-end-h').value = eh || '';
    document.getElementById('edit-end-m').value = em || '';
  } else {
    document.getElementById('edit-end-h').value = '';
    document.getElementById('edit-end-m').value = '';
  }
  document.getElementById('edit-modal-overlay').classList.add('show');
};

window._closeEditModal = () => {
  document.getElementById('edit-modal-overlay').classList.remove('show');
  editingStopId = null;
};

window._saveEditStop = async () => {
  const s = stoppages.find(x => x.id === editingStopId);
  if (!s) return;

  const sh = document.getElementById('edit-start-h').value;
  const sm = document.getElementById('edit-start-m').value;
  const eh = document.getElementById('edit-end-h').value;
  const em = document.getElementById('edit-end-m').value;

  if (!sh) { alert('Please select start time'); return; }

  const newStart = `${sh}:${sm}`;
  s.startDisplay = newStart;
  s.start = new Date(`${viewingDate}T${newStart}:00`).toISOString();

  if (eh && em && eh !== '--') {
    const newEnd = `${eh}:${em}`;
    s.endDisplay  = newEnd;
    s.end = new Date(`${viewingDate}T${newEnd}:00`).toISOString();
    const startMin = parseInt(sh)*60 + parseInt(sm);
    const endMin   = parseInt(eh)*60 + parseInt(em);
    s.durationMin  = endMin - startMin;
    if (s.durationMin < 0) s.durationMin += 24*60;
  } else {
    s.end = null;
    s.endDisplay  = null;
    s.durationMin = null;
  }

  await saveToFirestore();
  window._closeEditModal();
};

init();
